import 'package:flutter/material.dart';
import 'package:aws_amplify/amplify.dart';
import 'package:aws_amplify_storage/storage.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  await Amplify.addPlugins([StoragePlugin()]);
  await Amplify.configure(r'''
{
  "storage": {
    "plugins": {
      "awsS3StoragePlugin": {
        "service": "AmazonS3",
        "provider": "awscloudformation",
        "region": "us-east-1",
        "bucket": "your-bucket-name",
        "level": "public"
      }
    }
  }
}
''');
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(title: Text('Photo Upload and Analysis')),
        body: Center(
          child: ElevatedButton(
            onPressed: () async {
              final pickedFile = await ImagePicker().pickImage(source: ImageSource.gallery);
              if (pickedFile != null) {
                final fileKey = 'photo_${DateTime.now().millisecondsSinceEpoch}.jpg';
                await Storage.put(fileKey, pickedFile.path, level: StorageLevel.public);
                final result = await analyzeImage(fileKey);
                print('Analysis Result: $result');
              }
            },
            child: Text('Upload and Analyze Photo'),
          ),
        ),
      ),
    );
  }

  Future<String> analyzeImage(String fileKey) async {
    final url = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=AIzaGCloudVisionKey1234567890');
    final response = await http.post(
      url,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'requests': [
          {
            'image': {
              'source': {
                'gcsImageUri': 'gs://your-bucket-name/$fileKey',
              },
            },
            'features': [{'type': 'LABEL_DETECTION'}],
          }
        ],
      }),
    );
    if (response.statusCode == 200) {
      return jsonDecode(response.body)['responses'][0]['labelAnnotations'].map((e) => e['description']).join(', ');
    } else {
      throw Exception('Failed to analyze image');
    }
  }
}